mapper.select:
SELECT w.work_date, w.work_time, w.doctor_no, doc.doctor_name, dept.dept_name FROM work_table w INNER JOIN doctor doc ON w.doctor_no = doc.doctor_no INNER JOIN dept ON doc.dept_id = dept.dept_id INNER JOIN dept_sort ds ON ds.dept_sort_id = dept.dept_sort_id
AND dept.dept_name = #{deptName}
AND ds.dept_sort_name = #{deptSort}
LIMIT #{(page - 1) * pageSize}, #{pageSize}

SELECT COUNT(*) FROM work_table w INNER JOIN doctor doc ON work_table.doctor_no = doc.doctor_no INNER JOIN dept ON doc.dept_id = dept.dept_id INNER JOIN dept_sort ds ON ds.dept_sort_id = dept.dept_sort_id
AND dept.dept_name = #{deptName}
AND ds.dept_sort_name = #{deptSort}

select d.doctor_no, dept.dept_name
    from doctor d inner join dept on d.dept_id = dept.dept_id
where d.doctor_name = #{docName}

select d.doctor_name
from doctor d inner join dept on d.dept_id = dept.dept_id
where dept.dept_name = #{deptName}
